import React from 'react';

const ImageTextRow = ({ src, alt, link, text, reverse }) => (
  <a
    href={link}
    target="_blank"
    rel="noopener noreferrer"
    style={{
      ...styles.imageTextRow,
      flexDirection: reverse ? 'row-reverse' : 'row',
    }}
  >
    <img src={src} alt={alt} style={styles.image} />
    <div style={styles.textContainer}>
      <p style={styles.text}>{text}</p>
    </div>
  </a>
);

const ContactoPage = () => {
  const items = [
    {
      src: '/media/contactoPage/LP.png',
      alt: 'Entrada UCB',
      link: 'https://www.ucb.edu.bo/',
      text: 'Bienvenido a la Universidad Católica Boliviana',
    },
    {
      src: '/media/contactoPage/SIS - H.png',
      alt: 'Logo SIS',
      link: 'https://www.ucb.edu.bo/contacto',
      text: 'Sistema de Información y Servicios',
    },
    {
      src: '/media/contactoPage/IIE - H.png',
      alt: 'Equipo ADM',
      link: 'https://www.ucb.edu.bo/nosotros',
      text: 'Instituto de Investigaciones y Estudios',
    },
  ];

  return (
    <main style={styles.page}>
      <div style={styles.gridContainer}>
        {/* Área izquierda: texto + imágenes */}
        <section style={styles.textSection}>
          <h1 style={styles.title}>CONTACT US</h1>
          <p style={styles.paragraph}>
            If you have any questions or queries a member of staff will always be happy to help.
            Feel free to contact us by telephone or email and we will be sure to get back to you as soon as possible.
          </p>

          {/* Imágenes con texto y enlaces, alternando orden */}
          <div style={styles.imagesList}>
            {items.map((item, i) => (
              <ImageTextRow key={i} {...item} reverse={i % 2 === 1} />
            ))}
          </div>
        </section>

        {/* Área derecha: fondo azul con clip-path */}
        <section style={styles.imageSection}>
          {/* Puedes poner aquí fondo o imagen */}
        </section>

        {/* Bloques colores abajo */}
        <div style={styles.yellowBlock} />
        <div style={styles.greenBlock} />
      </div>
    </main>
  );
};

const styles = {
  page: {
    minHeight: '100vh',
    fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
    color: '#06232E',
  },
  gridContainer: {
    display: 'grid',
    gridTemplateColumns: '1fr 2fr',
    gridTemplateRows: '3fr 1fr',
    gap: 0,
    height: '100vh',
    backgroundColor: '#F5EEDD',
  },
  textSection: {
    gridColumn: '1 / 2',
    gridRow: '1 / 2',
    padding: '6rem 4rem',
    backgroundColor: '#F5EEDD',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
  },
  title: {
    fontSize: '3.5rem',
    fontWeight: '700',
    marginBottom: '1.5rem',
    color: '#06232E',
  },
  paragraph: {
    fontSize: '1.25rem',
    lineHeight: 1.7,
    maxWidth: 400,
    color: '#06232E',
    marginBottom: '3rem',
  },
  imagesList: {
    display: 'flex',
    flexDirection: 'column',
    gap: '2rem',
  },
  imageTextRow: {
    display: 'flex',
    alignItems: 'center',
    gap: '1.5rem',
    textDecoration: 'none',
    color: 'inherit',
    cursor: 'pointer',
  },
  image: {
    width: 140,
    height: 140,
    objectFit: 'cover',
    borderRadius: 16,
    flexShrink: 0,
    boxShadow: '0 2px 12px rgba(0,0,0,0.15)',
  },
  textContainer: {
    flex: 1,
  },
  text: {
    fontSize: '1.25rem',
    fontWeight: '600',
  },
  imageSection: {
    gridColumn: '2 / 3',
    gridRow: '1 / 3',
    backgroundColor: '#043D71',
    clipPath: 'polygon(0 0, 100% 0%, 100% 100%, 0 75%)',
    backgroundImage: 'url(/media/contactoPage/fondoGeom.png)', // Cambia o elimina si no tienes imagen
    backgroundSize: 'cover',
    backgroundPosition: 'center',
  },
  yellowBlock: {
    gridColumn: '1 / 2',
    gridRow: '2 / 3',
    backgroundColor: '#DDB35A',
  },
  greenBlock: {
    gridColumn: '2 / 3',
    gridRow: '2 / 3',
    backgroundColor: '#225C45',
  },
};

export default ContactoPage;
